mapper.select:
SELECT enroll.id AS id, grade.grade_group_name AS gradeName, cla.class_name AS className, stu.seat_no AS seatNo, stu.chinese_name AS studentName, stu.student_no AS studentNo, enroll.type AS type, enroll.graduate_type AS graduateType, enroll.job AS job, enroll.school_address AS schoolAddress, enroll.faculty AS faculty, enroll.department AS department FROM student_graduate_enroll enroll LEFT JOIN sys_class cla ON cla.id = enroll.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN student_info stu ON stu.id = enroll.student_id WHERE enroll.deleted = 0
AND stu.school_id = #{reqModel.schoolId}
AND cla.sid = #{reqModel.schoolYear}
AND cla.id = #{reqModel.classId}
AND (stu.chinese_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.english_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.student_no LIKE CONCAT('%', #{reqModel.studentInfo}, '%'))
AND enroll.type = #{reqModel.type}
AND enroll.graduate_type = #{reqModel.graduateType}
AND enroll.school_address = #{reqModel.schoolAddress}
AND cla.id IN
#{item}
order by enroll.create_time DESC
